args.command:
br list --json 2>&1 | grep -v "^Error" | python3 -c "
import sys, json
status_counts = {}
for line in sys.stdin:
    line = line.strip()
    if not line:
        continue
    try:
        bead = json.loads(line)
        assignee = bead.get('assignee', '')
        if assignee:  # Only beads with assignees
            status = bead.get('status', 'unknown')
            status_counts[status] = status_counts.get(status, 0) + 1
    except json.JSONDecodeError:
        pass

print('Status distribution of beads with assignees:')
for status, count in sorted(status_counts.items()):
    print(f'  {status}: {count}')
"
